20	// ddxSidecarFile is the YAML structure of a .ddx.yaml sidecar file.
21	type ddxSidecarFile struct {
22		DDx ddxSidecarMeta `yaml:"ddx"`
23	}
24	
25	type ddxSidecarMeta struct {
26		ID          string          `yaml:"id"`
27		Title       string          `yaml:"title"`
28		MediaType   string          `yaml:"media_type"`
29		Description string          `yaml:"description"`
30		GeneratedBy *ddxGeneratedBy `yaml:"generated_by"`
31	}
32	
33	type ddxGeneratedBy struct {
34		RunID         string `yaml:"run_id"`
35		PromptSummary string `yaml:"prompt_summary"`
36		SourceHash    string `yaml:"source_hash"`
37	}
