216	// collectArtifacts gathers all DDx-tracked artifacts from two sources:
217	//  1. The doc graph (markdown documents under the project root).
218	//  2. .ddx.yaml sidecar files under .ddx/plugins/.
219	func collectArtifacts(root string) ([]*Artifact, error) {
220		var artifacts []*Artifact
221	
222		// 1. Documents from the doc graph.
223		if docs, err := collectDocArtifacts(root); err == nil {
224			artifacts = append(artifacts, docs...)
225		}
226	
227		// 2. Sidecar artifacts from .ddx/plugins/.
228		if sidecars, err := collectSidecarArtifacts(root); err == nil {
229			artifacts = append(artifacts, sidecars...)
230		}
231	
232		return artifacts, nil
233	}
234	
235	// collectDocArtifacts builds Artifact records from the FEAT-007 doc graph.
236	func collectDocArtifacts(root string) ([]*Artifact, error) {
237		graph, err := docgraph.BuildGraphWithConfig(root)
238		if err != nil {
239			return nil, err
240		}
241	
242		staleSet := map[string]string{} // id → staleness ("stale" or "missing")
243		for _, entry := range graph.StaleDocs() {
244			staleness := "stale"
245			for _, reason := range entry.Reasons {
246				if strings.Contains(reason, "missing dependency") ||
247					strings.Contains(reason, "missing review hash") {
248					staleness = "missing"
249					break
250				}
251			}
252			staleSet[entry.ID] = staleness
253		}
254	
255		docs := graph.AllNodesForOutput()
256		out := make([]*Artifact, 0, len(docs))
257		for _, d := range docs {
258			staleness := "fresh"
259			if s, ok := staleSet[d.ID]; ok {
260				staleness = s
261			}
262	
263			a := &Artifact{
264				ID:        "doc:" + d.ID,
265				Path:      d.Path,
266				Title:     titleFromDoc(d),
267				MediaType: "text/markdown",
268				Staleness: staleness,
269			}
270	
271			// Populate updatedAt from file mod time.
272			absPath := d.Path
273			if !filepath.IsAbs(absPath) {
274				absPath = filepath.Join(graph.RootDir, absPath)
275			}
276			if info, statErr := os.Stat(absPath); statErr == nil {
277				ts := info.ModTime().UTC().Format(time.RFC3339)
278				a.UpdatedAt = &ts
279			}
280	
281			// Populate ddxFrontmatter as a JSON summary of available metadata.
282			frontmatter := map[string]interface{}{
283				"id": d.ID,
284			}
285			if len(d.DependsOn) > 0 {
286				frontmatter["depends_on"] = d.DependsOn
287			}
288			if d.Prompt != "" {
289				frontmatter["prompt"] = d.Prompt
290			}
291			if fm, err := json.Marshal(frontmatter); err == nil {
292				s := string(fm)
293				a.DdxFrontmatter = &s
294			}
295	
296			out = append(out, a)
297		}
298		return out, nil
299	}
300	
301	// collectSidecarArtifacts walks .ddx/plugins/ looking for *.ddx.yaml sidecar
302	// files, then builds an Artifact for each corresponding artifact file.
303	// Files whose sidecar is missing or unreadable are silently skipped.
304	func collectSidecarArtifacts(root string) ([]*Artifact, error) {
305		pluginsDir := filepath.Join(root, ".ddx", "plugins")
306		if _, err := os.Stat(pluginsDir); os.IsNotExist(err) {
307			return nil, nil
308		}
309	
310		var out []*Artifact
311		err := filepath.WalkDir(pluginsDir, func(path string, d fs.DirEntry, err error) error {
312			if err != nil || d.IsDir() {
313				return nil
314			}
315			if !strings.HasSuffix(path, ".ddx.yaml") {
316				return nil
317			}
318	
319			// Derive artifact path by stripping the .ddx.yaml suffix.
320			artifactPath := strings.TrimSuffix(path, ".ddx.yaml")
321	
322			// Parse the sidecar.
323			data, readErr := os.ReadFile(path)
324			if readErr != nil {
325				return nil // skip unreadable sidecars
326			}
327			var sidecar ddxSidecarFile
328			if yamlErr := yaml.Unmarshal(data, &sidecar); yamlErr != nil {
329				return nil // skip malformed sidecars
330			}
331	
332			rel, relErr := filepath.Rel(root, artifactPath)
333			if relErr != nil {
334				rel = artifactPath
335			}
336	
337			id := sidecar.DDx.ID
338			if id == "" {
339				id = "sidecar:" + rel
340			}
341	
342			title := sidecar.DDx.Title
343			if title == "" {
344				title = filepath.Base(artifactPath)
345			}
346	
347			mediaType := sidecar.DDx.MediaType
348			if mediaType == "" {
349				mediaType = "application/octet-stream"
350			}
351	
352			staleness := computeSidecarStaleness(artifactPath, sidecar.DDx.GeneratedBy)
353	
354			a := &Artifact{
355				ID:        id,
356				Path:      filepath.ToSlash(rel),
357				Title:     title,
358				MediaType: mediaType,
359				Staleness: staleness,
360			}
361	
362			if sidecar.DDx.Description != "" {
363				desc := sidecar.DDx.Description
364				a.Description = &desc
365			}
366	
367			if sidecar.DDx.GeneratedBy != nil {
368				gb := sidecar.DDx.GeneratedBy
369				sourceHashMatch := false
370				if gb.SourceHash != "" {
371					if hash, hashErr := fileSHA256(artifactPath); hashErr == nil {
372						sourceHashMatch = (hash == gb.SourceHash)
373					}
374				}
375				a.GeneratedBy = &ArtifactGeneratedBy{
376					RunID:           gb.RunID,
377					PromptSummary:   gb.PromptSummary,
378					SourceHashMatch: sourceHashMatch,
379				}
380			}
381	
382			// Populate ddxFrontmatter from the raw sidecar ddx block.
383			if fm, marshalErr := json.Marshal(sidecar.DDx); marshalErr == nil {
384				s := string(fm)
385				a.DdxFrontmatter = &s
386			}
387	
388			// Populate updatedAt from artifact file mod time.
389			if info, statErr := os.Stat(artifactPath); statErr == nil {
390				ts := info.ModTime().UTC().Format(time.RFC3339)
391				a.UpdatedAt = &ts
392			}
393	
394			out = append(out, a)
395			return nil
396		})
397		if err != nil {
398			return nil, err
399		}
400		return out, nil
401	}
402	
403	// computeSidecarStaleness returns the staleness of a sidecar artifact.
404	func computeSidecarStaleness(artifactPath string, gb *ddxGeneratedBy) string {
405		if _, err := os.Stat(artifactPath); os.IsNotExist(err) {
406			return "missing"
407		}
408		if gb == nil || gb.SourceHash == "" {
409			return "fresh"
410		}
411		hash, err := fileSHA256(artifactPath)
412		if err != nil {
413			return "fresh" // can't determine staleness without a hash
414		}
415		if hash == gb.SourceHash {
416			return "fresh"
417		}
418		return "stale"
419	}
420	
421	// fileSHA256 returns the hex-encoded SHA-256 hash of a file's contents.
422	func fileSHA256(path string) (string, error) {
423		data, err := os.ReadFile(path)
424		if err != nil {
425			return "", err
426		}
427		h := sha256.Sum256(data)
428		return hex.EncodeToString(h[:]), nil
429	}
430	
431	// titleFromDoc derives a human-readable title from a docgraph document.
432	// Uses the Title field if set, otherwise derives from the path's base name.
433	func titleFromDoc(d docgraph.Document) string {
434		if d.Title != "" {
435			return d.Title
436		}
437		base := filepath.Base(d.Path)
438		// Strip extension.
439		if idx := strings.LastIndex(base, "."); idx > 0 {
440			base = base[:idx]
441		}
442		return base
443	}
