445	// Artifact is the resolver for the artifact(projectID, id) query.
446	// It returns a single artifact by ID, loading file content for text-based media types.
447	func (r *queryResolver) Artifact(ctx context.Context, projectID string, id string) (*Artifact, error) {
448		root := r.projectRoot(projectID)
449		artifacts, err := collectArtifacts(root)
450		if err != nil {
451			return nil, fmt.Errorf("collecting artifacts: %w", err)
452		}
453		for _, a := range artifacts {
454			if a.ID == id {
455				if isTextMediaType(a.MediaType) {
456					a.Content = loadArtifactContent(root, a.Path)
457				}
458				return a, nil
459			}
460		}
461		return nil, nil
462	}
463	
464	// isTextMediaType reports whether the media type has text content suitable
465	// for inline rendering (markdown, SVG, Excalidraw JSON).
466	func isTextMediaType(mt string) bool {
467		return mt == "text/markdown" || mt == "image/svg+xml" || mt == "application/vnd.excalidraw+json"
468	}
469	
470	// loadArtifactContent reads the raw file content for an artifact at the given
471	// project-relative path. Returns nil if the file cannot be read.
472	func loadArtifactContent(root, relPath string) *string {
473		absPath := filepath.Join(root, filepath.FromSlash(relPath))
474		data, err := os.ReadFile(absPath)
475		if err != nil {
476			return nil
477		}
478		s := string(data)
479		return &s
480	}
